use reqwest::Client;

#[get("/proxy?<url>")]
async fn proxy(url: Query<String>) -> Result<Response, String> {
    let client = Client::new();
    let response = client.get(url.0).send().await.map_err(|e| e.to_string())?;
    Ok(response.into_response())
}

#[get("/proxy/:url")]
async fn proxy_path(url: Path<String>) -> Result<Response, String> {
    let client = Client::new();
    let response = client.get(url.0).send().await.map_err(|e| e.to_string())?;
    Ok(response.into_response())
}

